SEARCH_RESULT_SYSTEM_PROMPT = (
    "Ты — парфюмерный консультант. Отвечаешь кратко, по делу, без вступлений "
    "вроде «Отлично», «Конечно», «Давайте разберём». Сразу переходишь к сути. "
    "Ты представляешь подборку ароматов пользователю — всегда говори о них "
    "в позитивном ключе, подчёркивая сильные стороны каждого. Никогда не пиши, "
    "что аромат «не подходит» или «выбивается из подборки». "
    "Отвечаешь строго в JSON-формате без лишнего текста."
)


def build_search_result_prompt(query: str, perfumes: list[dict]) -> str:
    lines = []
    for i, p in enumerate(perfumes, 1):
        top = ", ".join(p.get("top_notes", [])) or "—"
        mid = ", ".join(p.get("middle_notes", [])) or "—"
        base = ", ".join(p.get("base_notes", [])) or "—"
        tags = ", ".join(p.get("tags", [])) if p.get("tags") else ""
        line = f"{i}. {p['brand']} — {p['name']}: верх {top} | сердце {mid} | база {base}"
        if tags:
            line += f" ({tags})"
        lines.append(line)
    perfume_list = "\n".join(lines)

    return f"""Запрос: «{query}»
Найденные ароматы:
{perfume_list}

Ответь ТОЛЬКО в JSON без markdown-обёртки:
{{
  "explanation": "Короткий текст (4–6 строк): одно предложение о том какие ноты объединяют подборку и почему они отвечают запросу, затем пара предложений об общем характере ароматов. Пиши на русском, живым языком. Не перечисляй каждый аромат отдельно.",
  "pyramid": {{
    "top": ["нота1", "нота2"],
    "middle": ["нота1", "нота2"],
    "base": ["нота1", "нота2"]
  }}
}}

Для pyramid выбери 2–4 самые характерные реальные ноты на каждый уровень из нот найденных ароматов — те что лучше всего отражают суть подборки."""
